const Persist = {
  KEY: 'fph.workspace.v2',
  _t: null,
  save(ws) {
    clearTimeout(this._t);
    this._t = setTimeout(() => {
      try { localStorage.setItem(this.KEY, JSON.stringify(ws)); }
      catch (e) { View.showBanner('warn', 'Auto-save unavailable: ' + e.name); }
    }, 500);
  },
  load() {
    try {
      const raw = localStorage.getItem(this.KEY);
      if (!raw) return null;
      const ws = JSON.parse(raw);
      if (ws.schemaVersion !== 2) return null; // discard unknown schema
      return ws;
    } catch { return null; }
  },
  clear() { localStorage.removeItem(this.KEY); }
};
Store.subscribe(ws => Persist.save(ws));
